<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;管理员策略阻止外部成员&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
